      {sessionActive && (
        <AvatarPiP videoRef={avatar.videoRef} isReady={avatar.isReady} />
      )}

      {/* Gesture visual feedback */}
      <GestureIndicator key={gestureKey} gesture={lastGesture} />

      {/* Product carousel (bottom) */}
      <ProductCarousel
        items={products}
        onGesture={(gesture, item) => {
          console.log("[Mirror] Carousel gesture:", gesture, item.title);
        }}
      />

      {/* Voice indicator (bottom-left) */}
      {sessionActive && (
        <VoiceIndicator
          isListening={stt.isListening}
          interimTranscript={stt.interimTranscript}
        />
      )}

      {/* Status indicators */}
      {(cameraError || modelError) && (
        <div
          style={{
            position: "absolute",
            bottom: 20,
            left: 20,
            color: "#f44",
            fontSize: "1rem",
            zIndex: 30,
          }}
        >
          {cameraError && <div>Camera: {cameraError}</div>}
          {modelError && <div>Model: {modelError}</div>}
        </div>
      )}

      {/* Mirror text overlay from Poke */}
      {mirrorText && (
        <div
          style={{
            position: "absolute",
            top: 40,
            left: "50%",
            transform: "translateX(-50%)",
            maxWidth: "80%",
            padding: "16px 24px",
            background: "rgba(0, 0, 0, 0.75)",
            borderRadius: 12,
            color: "#fff",
            fontSize: "1.25rem",
            lineHeight: 1.5,
            textAlign: "center",
            zIndex: 40,
            backdropFilter: "blur(8px)",
          }}
        >
          {mirrorText}
        </div>
      )}

      {/* Mirror ID badge (top-left) */}
      <div
        style={{
          position: "absolute",
          top: 12,
          left: 12,
          padding: "4px 10px",
          background: "rgba(255, 255, 255, 0.15)",
          borderRadius: 6,
          color: "rgba(255, 255, 255, 0.6)",
          fontSize: "0.75rem",
          fontFamily: "monospace",
          zIndex: 50,
        }}
      >
        {mirrorId}
      </div>

      {isModelLoading && (
        <div
          style={{
            position: "absolute",
            top: "50%",
            left: "50%",
            transform: "translate(-50%, -50%)",
            color: "#fff",
            fontSize: "1.5rem",
            zIndex: 30,
          }}
        >
          Loading gesture recognition...
        </div>
      )}
    </main>
  );
}

