          fontSize: "0.75rem",
          fontFamily: "monospace",
          zIndex: 50,
        }}
      >
        {mirrorId}
      </div>

      {isModelLoading && (
        <div
          style={{
            position: "absolute",
            top: "50%",
            left: "50%",
            transform: "translate(-50%, -50%)",
            color: "#fff",
            fontSize: "1.5rem",
            zIndex: 30,
          }}
        >
          Loading gesture recognition...
        </div>
      )}
    </main>
  );
}

