"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import StreamingAvatar, {
  AvatarQuality,
  StreamingEvents,
  TaskType,
} from "@heygen/streaming-avatar";

const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";
// HeyGen default public avatar; override via NEXT_PUBLIC_HEYGEN_AVATAR_ID
const AVATAR_ID =
  process.env.NEXT_PUBLIC_HEYGEN_AVATAR_ID || "default";

export interface UseHeyGenAvatarReturn {
  isReady: boolean;
  isSpeaking: boolean;
  startAvatar: () => Promise<void>;
  stopAvatar: () => Promise<void>;
  speak: (text: string) => Promise<void>;
  interrupt: () => Promise<void>;
  clearQueue: () => void;
  videoRef: React.RefObject<HTMLVideoElement | null>;
}

async function fetchToken(): Promise<string> {
  const res = await fetch(`${API_URL}/api/heygen/token`);
  if (!res.ok) throw new Error(`Failed to fetch HeyGen token: ${res.status}`);
  const data = await res.json();
  return data.token;
}

export function useHeyGenAvatar(): UseHeyGenAvatarReturn {
  const [isReady, setIsReady] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const avatarRef = useRef<StreamingAvatar | null>(null);

  // Speech queue — process one sentence at a time to prevent HeyGen garbling
  const speechQueueRef = useRef<string[]>([]);
  const isProcessingQueueRef = useRef(false);

  const processQueue = useCallback(async () => {
    if (isProcessingQueueRef.current || !avatarRef.current) return;
    const next = speechQueueRef.current.shift();
    if (!next) {
      setIsSpeaking(false);
      return;
    }
    isProcessingQueueRef.current = true;
    setIsSpeaking(true);
    try {
      await avatarRef.current.speak({ text: next, taskType: TaskType.REPEAT });
    } catch (err) {
      console.error("[HeyGen] speak() failed:", err);
      // Reset and try next in queue
      isProcessingQueueRef.current = false;
      processQueue();
    }
    // isProcessingQueueRef is reset by AVATAR_STOP_TALKING handler
  }, []);

  const clearQueue = useCallback(() => {
    speechQueueRef.current = [];
    isProcessingQueueRef.current = false;
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      clearQueue();
      avatarRef.current?.stopAvatar();
      avatarRef.current = null;
    };
  }, [clearQueue]);

  const startAvatar = useCallback(async () => {
    if (avatarRef.current) return;

    const token = await fetchToken();
    const avatar = new StreamingAvatar({ token });
    avatarRef.current = avatar;

    avatar.on(StreamingEvents.STREAM_READY, (event: { detail: MediaStream }) => {
      if (videoRef.current && event.detail) {
        videoRef.current.srcObject = event.detail;
        videoRef.current.play().catch(() => {});
      }
      setIsReady(true);
    });

    avatar.on(StreamingEvents.AVATAR_START_TALKING, () => {
      setIsSpeaking(true);
    });

    avatar.on(StreamingEvents.AVATAR_STOP_TALKING, () => {
      isProcessingQueueRef.current = false;
      processQueue(); // Speak next queued sentence, or set isSpeaking=false
    });

    avatar.on(StreamingEvents.STREAM_DISCONNECTED, () => {
      setIsReady(false);
      setIsSpeaking(false);
      clearQueue();
      avatarRef.current = null;
    });

    await avatar.createStartAvatar({
      quality: AvatarQuality.Medium,
      avatarName: AVATAR_ID,
    });
  }, [processQueue, clearQueue]);

  const stopAvatar = useCallback(async () => {
    if (!avatarRef.current) return;
    clearQueue();
    await avatarRef.current.stopAvatar();
    avatarRef.current = null;
    setIsReady(false);
    setIsSpeaking(false);
    if (videoRef.current) {
      videoRef.current.srcObject = null;
    }
  }, [clearQueue]);

  const speak = useCallback(async (text: string) => {
    if (!text.trim()) return;
    speechQueueRef.current.push(text);
    setIsSpeaking(true); // Immediately show speaking state
    processQueue();
  }, [processQueue]);

  const interrupt = useCallback(async () => {
    if (!avatarRef.current) return;
    clearQueue();
    await avatarRef.current.interrupt();
  }, [clearQueue]);

  return { isReady, isSpeaking, startAvatar, stopAvatar, speak, interrupt, clearQueue, videoRef };
}

