     1→"use client";
     2→
     3→import { useCallback, useEffect, useRef, useState } from "react";
     4→import StreamingAvatar, {
     5→  AvatarQuality,
     6→  StreamingEvents,
     7→  TaskType,
     8→} from "@heygen/streaming-avatar";
     9→
    10→const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";
    11→// HeyGen default public avatar; override via NEXT_PUBLIC_HEYGEN_AVATAR_ID
    12→const AVATAR_ID =
    13→  process.env.NEXT_PUBLIC_HEYGEN_AVATAR_ID || "default";
    14→
    15→export interface UseHeyGenAvatarReturn {
    16→  isReady: boolean;
    17→  isSpeaking: boolean;
    18→  startAvatar: () => Promise<void>;
    19→  stopAvatar: () => Promise<void>;
    20→  speak: (text: string) => Promise<void>;
    21→  interrupt: () => Promise<void>;
    22→  clearQueue: () => void;
    23→  videoRef: React.RefObject<HTMLVideoElement | null>;
    24→}
    25→
    26→async function fetchToken(): Promise<string> {
    27→  const res = await fetch(`${API_URL}/api/heygen/token`);
    28→  if (!res.ok) throw new Error(`Failed to fetch HeyGen token: ${res.status}`);
    29→  const data = await res.json();
    30→  return data.token;
    31→}
    32→
    33→export function useHeyGenAvatar(): UseHeyGenAvatarReturn {
    34→  const [isReady, setIsReady] = useState(false);
    35→  const [isSpeaking, setIsSpeaking] = useState(false);
    36→  const videoRef = useRef<HTMLVideoElement | null>(null);
    37→  const avatarRef = useRef<StreamingAvatar | null>(null);
    38→
    39→  // Speech queue — process one sentence at a time to prevent HeyGen garbling
    40→  const speechQueueRef = useRef<string[]>([]);
    41→  const isProcessingQueueRef = useRef(false);
    42→
    43→  const processQueue = useCallback(async () => {
    44→    if (isProcessingQueueRef.current || !avatarRef.current) return;
    45→    const next = speechQueueRef.current.shift();
    46→    if (!next) {
    47→      setIsSpeaking(false);
    48→      return;
    49→    }
    50→    isProcessingQueueRef.current = true;
    51→    setIsSpeaking(true);
    52→    try {
    53→      await avatarRef.current.speak({ text: next, taskType: TaskType.REPEAT });
    54→    } catch (err) {
    55→      console.error("[HeyGen] speak() failed:", err);
    56→      // Reset and try next in queue
    57→      isProcessingQueueRef.current = false;
    58→      processQueue();
    59→    }
    60→    // isProcessingQueueRef is reset by AVATAR_STOP_TALKING handler
    61→  }, []);
    62→
    63→  const clearQueue = useCallback(() => {
    64→    speechQueueRef.current = [];
    65→    isProcessingQueueRef.current = false;
    66→  }, []);
    67→
    68→  // Cleanup on unmount
    69→  useEffect(() => {
    70→    return () => {
    71→      clearQueue();
    72→      avatarRef.current?.stopAvatar();
    73→      avatarRef.current = null;
    74→    };
    75→  }, [clearQueue]);
    76→
    77→  const startAvatar = useCallback(async () => {
    78→    if (avatarRef.current) return;
    79→
    80→    const token = await fetchToken();
    81→    const avatar = new StreamingAvatar({ token });
    82→    avatarRef.current = avatar;
    83→
    84→    avatar.on(StreamingEvents.STREAM_READY, (event: { detail: MediaStream }) => {
    85→      if (videoRef.current && event.detail) {
    86→        videoRef.current.srcObject = event.detail;
    87→        videoRef.current.play().catch(() => {});
    88→      }
    89→      setIsReady(true);
    90→    });
    91→
    92→    avatar.on(StreamingEvents.AVATAR_START_TALKING, () => {
    93→      setIsSpeaking(true);
    94→    });
    95→
    96→    avatar.on(StreamingEvents.AVATAR_STOP_TALKING, () => {
    97→      isProcessingQueueRef.current = false;
    98→      processQueue(); // Speak next queued sentence, or set isSpeaking=false
    99→    });
   100→
   101→    avatar.on(StreamingEvents.STREAM_DISCONNECTED, () => {
   102→      setIsReady(false);
   103→      setIsSpeaking(false);
   104→      clearQueue();
   105→      avatarRef.current = null;
   106→    });
   107→
   108→    await avatar.createStartAvatar({
   109→      quality: AvatarQuality.Medium,
   110→      avatarName: AVATAR_ID,
   111→    });
   112→  }, [processQueue, clearQueue]);
   113→
   114→  const stopAvatar = useCallback(async () => {
   115→    if (!avatarRef.current) return;
   116→    clearQueue();
   117→    await avatarRef.current.stopAvatar();
   118→    avatarRef.current = null;
   119→    setIsReady(false);
   120→    setIsSpeaking(false);
   121→    if (videoRef.current) {
   122→      videoRef.current.srcObject = null;
   123→    }
   124→  }, [clearQueue]);
   125→
   126→  const speak = useCallback(async (text: string) => {
   127→    if (!text.trim()) return;
   128→    speechQueueRef.current.push(text);
   129→    setIsSpeaking(true); // Immediately show speaking state
   130→    processQueue();
   131→  }, [processQueue]);
   132→
   133→  const interrupt = useCallback(async () => {
   134→    if (!avatarRef.current) return;
   135→    clearQueue();
   136→    await avatarRef.current.interrupt();
   137→  }, [clearQueue]);
   138→
   139→  return { isReady, isSpeaking, startAvatar, stopAvatar, speak, interrupt, clearQueue, videoRef };
   140→}
