    18→
    19→export default function MirrorPageWrapper() {
    20→  return (
    21→    <Suspense fallback={null}>
    22→      <MirrorPage />
    23→    </Suspense>
    24→  );
    25→}
    26→
    27→function MirrorPage() {
    28→  const searchParams = useSearchParams();
    29→  const userId = searchParams.get("user_id");
    30→  const mirrorId = searchParams.get("mirror_id") ?? process.env.NEXT_PUBLIC_MIRROR_ID ?? "MIRROR-A1";
    31→  const { videoRef, isReady: isCameraReady, error: cameraError } = useCamera();
    32→
    33→  // Gesture state (existing)
    34→  const [lastGesture, setLastGesture] = useState<GestureType | null>(null);
    35→  const gestureKeyRef = useRef(0);
    36→  const [gestureKey, setGestureKey] = useState(0);
    37→
    38→  // Session state
    39→  const [sessionActive, setSessionActive] = useState(false);
    40→  const [isStarting, setIsStarting] = useState(false);
    41→  const [products, setProducts] = useState<ProductCard[]>([]);
    42→
    43→  // Mirror text overlay from Poke (via send_to_mirror)
    44→  const [mirrorText, setMirrorText] = useState<string | null>(null);
    45→  const mirrorTextTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    46→
    47→  // Hooks for avatar + voice
    48→  const avatar = useHeyGenAvatar();
    49→  const stt = useDeepgramSTT();
    50→
    51→  // Pending transcripts queue (held while Mira is speaking)
    52→  const pendingTranscriptsRef = useRef<string[]>([]);
    53→
    54→  // Sentence buffer: accumulates mira_speech chunks → calls avatar.speak per sentence
    55→  const sentenceBufferRef = useRef<SentenceBuffer | null>(null);
    56→  useEffect(() => {
    57→    sentenceBufferRef.current = new SentenceBuffer((sentence) => {
    58→      avatar.speak(sentence);
    59→    });
    60→  }, [avatar.speak]);
    61→
    62→  // --------------- Socket connection ---------------
    63→
    64→  useEffect(() => {
    65→    socket.connect();
    66→
    67→    // Join mirror room (for Poke-driven events via MCP bridge)
    68→    socket.emit("join_room", {
    69→      mirror_id: mirrorId,
    70→      ...(userId ? { user_id: userId } : {}),
    71→    });
    72→
    73→    return () => {
    74→      socket.disconnect();
    75→    };
    76→  }, [userId, mirrorId]);
    77→
    78→  // --------------- Snapshot handler (existing) ---------------
    79→
    80→  useEffect(() => {
    81→    const handleSnapshotRequest = () => {
    82→      const video = videoRef.current;
    83→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
    84→
    85→      const canvas = document.createElement("canvas");
    86→      canvas.width = video.videoWidth;
    87→      canvas.height = video.videoHeight;
    88→      const ctx = canvas.getContext("2d");
    89→      if (!ctx) return;
    90→
    91→      ctx.drawImage(video, 0, 0);
    92→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
    93→      const base64 = dataUrl.split(",")[1];
    94→
    95→      socket.emit("mirror_event", {
    96→        type: "snapshot",
    97→        image_base64: base64,
    98→        user_id: userId,
    99→      });
   100→    };
   101→
   102→    socket.on("request_snapshot", handleSnapshotRequest);
   103→    return () => {
   104→      socket.off("request_snapshot", handleSnapshotRequest);
   105→    };
   106→  }, [videoRef, userId]);
   107→
   108→  // --------------- Mira speech streaming ---------------
   109→
   110→  useEffect(() => {
   111→    const handleMiraSpeech = (data: { text: string; is_chunk: boolean }) => {
   112→      if (data.is_chunk) {
   113→        sentenceBufferRef.current?.feed(data.text);
