   117→      }
   118→    };
   119→
   120→    socket.on("mira_speech", handleMiraSpeech);
   121→    return () => {
   122→      socket.off("mira_speech", handleMiraSpeech);
   123→    };
   124→  }, []);
   125→
   126→  // --------------- Tool results (product carousel) ---------------
   127→
   128→  useEffect(() => {
   129→    const handleToolResult = (data: { type: string; items?: ProductCard[] }) => {
   130→      if (data.type === "clothing_results" && data.items) {
   131→        setProducts(data.items);
   132→      }
   133→    };
   134→
   135→    socket.on("tool_result", handleToolResult);
   136→    return () => {
   137→      socket.off("tool_result", handleToolResult);
   138→    };
   139→  }, []);
   140→
   141→  // --------------- Mirror text from Poke (via send_to_mirror) ---------------
   142→
   143→  useEffect(() => {
   144→    const handleMirrorText = (data: { text: string }) => {
   145→      setMirrorText(data.text);
   146→
   147→      // Auto-clear after 15 seconds
   148→      if (mirrorTextTimeoutRef.current) {
   149→        clearTimeout(mirrorTextTimeoutRef.current);
   150→      }
   151→      mirrorTextTimeoutRef.current = setTimeout(() => setMirrorText(null), 15000);
   152→
   153→      // Speak via TTS (uses the existing avatar or browser speech synthesis)
   154→      if (avatar.isReady) {
   155→        avatar.speak(data.text);
   156→      } else if ("speechSynthesis" in window) {
   157→        const utterance = new SpeechSynthesisUtterance(data.text);
   158→        speechSynthesis.speak(utterance);
