   161→
   162→    socket.on("mirror_text", handleMirrorText);
   163→    return () => {
   164→      socket.off("mirror_text", handleMirrorText);
   165→      if (mirrorTextTimeoutRef.current) {
   166→        clearTimeout(mirrorTextTimeoutRef.current);
