   197→
   198→    return () => {
   199→      socket.off("session_active", handleSessionStarted);
   200→      socket.off("session_ended", handleSessionEnded);
   201→      socket.off("session_error", handleSessionError);
   202→    };
   203→  }, [avatar.startAvatar, avatar.stopAvatar, avatar.clearQueue, stt.startListening, stt.stopListening]);
   204→
   205→  // Fallback: auto-detect session start from first mira_speech if session_active isn't emitted
